class WordDictionary:
    def __init__(self):
        self.children = {}
        self.end = False

    def addWord(self, word):
        node = self
        for ch in word:
            node = node.children.setdefault(ch, WordDictionary())
        node.end = True

    def search(self, word):
        def dfs(index, node):
            if index == len(word):
                return node.end
            ch = word[index]
            if ch == '.':
                return any(dfs(index + 1, child) for child in node.children.values())
            return ch in node.children and dfs(index + 1, node.children[ch])
        return dfs(0, self)

class Solution:
    def wordDictionary(self, operations, values):
        wd = None
        out = []
        for op, args in zip(operations, values):
            if op == 'WordDictionary':
                wd = WordDictionary()
            elif op == 'addWord':
                wd.addWord(args[0])
            elif op == 'search':
                out.append(wd.search(args[0]))
        return out
